func permutations(s string) []string {
    result := make([]string, 0)
    used := make([]bool, len(s))
    path := make([]byte, 0, len(s))

    var backtrack func()
    backtrack = func() {
        if len(path) == len(s) {
            result = append(result, string(path))
            return
